// --------------------------
// Sensing Components
// --------------------------

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor (I_M) measuring the electrical current of the permanent‑magnet synchronous motor on the first axis."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑side position encoder providing angular position and velocity of the motor shaft."
    DTDFVocab:producedData MotorSideEncoderDataTransmitted
]

instance GearboxSideEncoder : DTDFVocab:SensingComponent [
    base:desc "Gearbox‑side position encoder providing angular position and velocity after the gearwheel gearbox."
    DTDFVocab:producedData GearboxSideEncoderDataTransmitted
]

// --------------------------
// Physical‑to‑Virtual Interaction (Data Transmitted)
// --------------------------

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
    base:desc "Live motor current I_M values streamed as time‑series via MQTT from the robot to the digital shadow."
]

instance MotorSideEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorSideEncoder
    base:desc "Motor‑side encoder angle and velocity streamed via MQTT as time‑series."
]

instance GearboxSideEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxSideEncoder
    base:desc "Gearbox‑side encoder angle and velocity streamed via MQTT as time‑series."
]

// --------------------------
// Data Traces
// --------------------------

instance CurrentDataTrace : DTDFVocab:Data [
    base:desc "Time‑series trace of motor current I_M used for friction identification."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo SimulinkEngine, DashboardVisualization
]

instance MotorEncoderDataTrace : DTDFVocab:Data [
    base:desc "Time‑series trace of motor‑side encoder angular position and velocity."
    DTDFVocab:fromData MotorSideEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkEngine, DashboardVisualization
]

instance GearboxEncoderDataTrace : DTDFVocab:Data [
    base:desc "Time‑series trace of gearbox‑side encoder angular position and velocity."
    DTDFVocab:fromData GearboxSideEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkEngine, DashboardVisualization
]

// --------------------------
// Enablers (Tooling & Infrastructure)
// --------------------------

instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML tooling used for structural and behavioral modeling of the motor, gearwheel and cycloidal gearbox."
    DTDFVocab:enables EngineeringModelIntegrationService
]

instance SimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink simulation environment executing friction‑free drivetrain and various friction models."
    DTDFVocab:enables RealTimeFrictionIdentificationService,
                       DataVisualizationService,
                       FrictionParameterUpdateService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell (AAS) that integrates engineering models and delivers updated friction parameters to the robot controller."
    DTDFVocab:enables FrictionParameterUpdateService,
                       EngineeringModelIntegrationService
]

instance MqttBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker that transports live sensor time‑series from the robot to the digital twin."
    DTDFVocab:enables RealTimeFrictionIdentificationService,
                       DataVisualizationService
]

instance DashboardVisualization : DTDFVocab:Enabler [
    base:desc "Custom dashboard visualizing measured and simulated data streams in real time."
    DTDFVocab:enables DataVisualizationService
]

// --------------------------
// Services
// --------------------------

instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Identifies static, kinetic and viscous friction coefficients in real time from measured current and encoder data."
    DTDFVocab:provides FrictionParameterInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Displays measured and simulated torque, velocity and current traces on a unified dashboard."
    DTDFVocab:provides DataVisualizationInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generates updated friction parameters and feeds them back to the robot controller to improve model‑based motion control."
    DTDFVocab:provides UpdateFrictionParametersAction
]

instance EngineeringModelIntegrationService : DTDFVocab:Service [
    base:desc "Integrates SysML engineering models into the digital twin via the Asset Administration Shell."
    DTDFVocab:provides EngineeringModelIntegrationInsight
]

// --------------------------
// Insights & Actions
// --------------------------

instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Derived friction parameters (static, kinetic, viscous coefficients) obtained from real‑time identification."
]

instance DataVisualizationInsight : DTDFVocab:Insight [
    base:desc "Measured and simulated data align, confirming the validity of the selected friction model."
]

instance EngineeringModelIntegrationInsight : DTDFVocab:Insight [
    base:desc "Successful binding of SysML models to the digital twin through the Asset Administration Shell."
]

instance UpdateFrictionParametersAction : DTDFVocab:Action [
    base:desc "Automatic update of friction coefficients in the robot controller to reduce positioning errors."
    DTDFVocab:IsAutomatic true
]

