]

instance SysMLCycloidalGearboxModel : DTDFVocab:Model [
    base:desc "SysML model of the cycloidal gearbox used for machining operations on the first axis."
    DTDFVocab:inputTo AssetAdministrationShell
]

instance SimulinkFrictionFreeDrivetrainModel : DTDFVocab:Model [
